import React, { useCallback, useMemo, useRef, useState } from 'react';
import type { CustomerGroupNavSelection } from '../../../components/dm/CustomerGroupCascadeNav/CustomerGroupCascadeNav';
import {
  LIN_TREE_GRID_TABLE_CARD_CLASS,
  LinListFilterField,
  LinTreeGridLayout,
  SearchTextInput,
  Select,
  dispatchAppToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
  useViewMobileLayout,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { masterService } from '../../../services/master/masterService';
import { exportCustomersCsv } from '../../../services/master/catalogExport';
import type { CustomerGroupDto, CustomerListItemDto } from '../../../services/master/models';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import { useCatalogListPermissions } from '../../../hooks/useCatalogListPermissions';
import { useCatalogReloadOnCompanyChange } from '../../../hooks/useCatalogReloadOnCompanyChange';
import {
  useCatalogListPaging,
  useCatalogPagination,
  useServerPagedListLoading,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
  CatalogCodeReplaceProvider,
  CatalogListHeaderFilters,
  CatalogListMasterLinPageLayout,
  CatalogListExportButton,
  CatalogRowActionMenu,
  type CatalogRowMenuAction,
  type CatalogListToolbarBridge,
} from '../../../components/catalog';
import { getSharedCatalogEditBlockedMessage, catalogRowEditHintDismissStorageKey } from '../../../utils/sharedCatalogEditBlockedMessage';
import {
  getErpListRowMenuHint,
  catalogListRowMenuHintDismissStorageKey,
} from '../../../utils/catalogListRowMenuHint';
import {
  CatalogListGridFromSchema,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  listVisibleFields,
  proposalEditableFields,
  toProposalFieldDefs,
  type ErpListSortState,
} from '../../../components/catalog/catalogUiSchema';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import { CustomerForm } from '../../../components/dm/CustomerForm';
import {
  buildCustomerGroupSelectOptions,
  buildCustomerGroupTypeCountMap,
  buildCustomerTypeNavCountMap,
  CUSTOMER_GROUP_TREE_PRELOAD_SIZE,
  isCustomerGroupNavEmpty,
  type CustomerTypeNavCounts,
  normalizeCustomerGroupDto,
  resolveCustomerTypeLabel,
} from '../../../utils/customerGroupTree';
import { CustomerGroupCascadeNav } from '../../../components/dm/CustomerGroupCascadeNav/CustomerGroupCascadeNav';
import { resolveInitOptionLabel } from '../../../utils/initOptionLabel';
import {
  flattenCustomerTree,
  buildCustomerDepthMap,
  customerRowDepth,
  CUSTOMER_INDENT_PX,
  normalizeCustomerDto,
} from '../../../utils/customerTree';
import {
  filterCatalogListRows,
  applyCatalogColumnFilters,
  applyCatalogColumnSort,
  catalogCellDisplayTextForKey,
} from '../../../utils/catalogListClientSearch';
import styles from '../../../styles/erpPage.module.css';
import { selectPlaceholderClass } from '../../../utils/selectField';

const TEST_ID = 'dm-doi-tuong';
const CATALOG_KIND = 'customers';

type CustomerGridRow = CustomerListItemDto & { id: string };

type CreateCustomerPreset = {
  defaultCustomerGroupId?: string;
  defaultCustomerType?: string;
  defaultParentCustomer?: CustomerListItemDto | null;
};

const DoiTuongPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const viewMobile = useViewMobileLayout();
  const toolbarBridgeRef = useRef<CatalogListToolbarBridge | null>(null);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: CustomerGridRow } | null>(null);
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [groupNavSelection, setGroupNavSelection] = useState<CustomerGroupNavSelection>({ kind: 'all' });
  const [customerGroups, setCustomerGroups] = useState<CustomerGroupDto[]>([]);
  const [typeNavCounts, setTypeNavCounts] = useState<CustomerTypeNavCounts | null>(null);
  const [items, setItems] = useState<CustomerListItemDto[]>([]);
  const [serverTotalCount, setServerTotalCount] = useState(0);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<CustomerListItemDto | null>(null);
  const [reloadKey, setReloadKey] = useState(0);
  const [formViewOnly, setFormViewOnly] = useState(false);
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);
  const [columnFilters, setColumnFilters] = useState<Record<string, string[]>>({});
  const [sortState, setSortState] = useState<ErpListSortState>(null);
  const [gridNavLoading, setGridNavLoading] = useState(false);
  const [createPreset, setCreatePreset] = useState<CreateCustomerPreset>({});
  const [createSessionKey, setCreateSessionKey] = useState(0);
  const fetchLoadingKindRef = useRef<'nav' | 'default'>('default');

  const { canWrite } = useCatalogListPermissions(CATALOG_KIND);

  const companyReloadKey = useCatalogReloadOnCompanyChange();

  const { schema, loading: schemaLoading, reload: reloadSchema } = useCatalogUiSchema(CATALOG_KIND);
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);
  const proposalFieldDefs = useMemo(
    () => toProposalFieldDefs(proposalEditableFields(schema)),
    [schema],
  );

  const customerGroupFilter =
    groupNavSelection.kind === 'group' ? groupNavSelection.customerGroupId : '';
  const customerTypeFilter =
    groupNavSelection.kind === 'type' ? groupNavSelection.customerType : undefined;

  const isTreeMode = search.trim().length === 0 && !customerGroupFilter && !customerTypeFilter;

  const { customerGroupOptions: listGroupOptions, customerTypeOptions } = useVoucherInitData('customer-list');
  const initFormName = modalOpen && editing ? 'edit-customer' : 'create-customer';

  const locallyFilteredItems = useMemo(
    () =>
      filterCatalogListRows(
        items as unknown as Record<string, unknown>[],
        searchDraft,
        listColumns,
        row => {
          const c = row as unknown as CustomerListItemDto;
          const typeLabel = resolveInitOptionLabel(customerTypeOptions, c.customerType);
          return typeLabel ? [typeLabel] : [];
        },
      ) as unknown as CustomerListItemDto[],
    [items, searchDraft, listColumns, customerTypeOptions],
  );

  const columnFilteredItems = useMemo(
    () =>
      applyCatalogColumnFilters(
        locallyFilteredItems as unknown as Record<string, unknown>[],
        listColumns,
        columnFilters,
      ) as unknown as CustomerListItemDto[],
    [locallyFilteredItems, listColumns, columnFilters],
  );

  const sortedItems = useMemo(
    () =>
      applyCatalogColumnSort(
        columnFilteredItems as unknown as Record<string, unknown>[],
        listColumns,
        sortState,
      ) as unknown as CustomerListItemDto[],
    [columnFilteredItems, listColumns, sortState],
  );

  const displayRows = useMemo(
    () => (isTreeMode ? flattenCustomerTree(sortedItems) : sortedItems),
    [sortedItems, isTreeMode],
  );

  const depthMap = useMemo(() => buildCustomerDepthMap(sortedItems), [sortedItems]);

  const typeCounts = useMemo(
    () => buildCustomerGroupTypeCountMap(customerGroups, typeNavCounts),
    [customerGroups, typeNavCounts],
  );

  const navSelectionEmpty = useMemo(
    () => isCustomerGroupNavEmpty(groupNavSelection, customerGroups, typeCounts),
    [groupNavSelection, customerGroups, typeCounts],
  );

  const allTypeTotalCount = useMemo(
    () => serverTotalCount,
    [serverTotalCount],
  );

  const groupOpts = useMemo(() => {
    if (listGroupOptions.length > 0) return listGroupOptions;
    return buildCustomerGroupSelectOptions(customerGroups);
  }, [listGroupOptions, customerGroups]);

  const filterGroupOpts = useMemo(() => {
    if (listGroupOptions.length > 0) return listGroupOptions;
    return buildCustomerGroupSelectOptions(customerGroups);
  }, [listGroupOptions, customerGroups]);

  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const {
    page: serverPage,
    setPage: setServerPage,
    pageSize: serverPageSize,
    setPageSize: setServerPageSize,
    resetPage: resetServerPage,
  } = useCatalogListPaging();
  const {
    showTableLoading,
    pageLoading,
    pulseSearch,
    setLoadingMode,
    beginFetch,
    endFetch,
  } = useServerPagedListLoading();

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      masterService.getCustomerGroups({
        page: 1,
        pageSize: CUSTOMER_GROUP_TREE_PRELOAD_SIZE,
        isActive: true,
      })
        .then(data => {
          if (!cancelled) {
            setCustomerGroups(data.items.map(normalizeCustomerGroupDto));
          }
        })
        .catch(() => { /* non-blocking */ });
      masterService.getCustomerTypeCounts()
        .then(data => {
          if (!cancelled) {
            setTypeNavCounts(buildCustomerTypeNavCountMap(data));
          }
        })
        .catch(() => { /* non-blocking */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [reloadKey, companyReloadKey]);

  React.useEffect(() => {
    let cancelled = false;
    const isNavFetch = fetchLoadingKindRef.current === 'nav';
    fetchLoadingKindRef.current = 'default';

    if (navSelectionEmpty) {
      setItems([]);
      setServerTotalCount(0);
      if (isNavFetch) setGridNavLoading(false);
      return () => { cancelled = true; };
    }

    if (!isNavFetch) {
      beginFetch();
    }
    const t = setTimeout(() => {
      masterService.getCustomers({
        search: search || undefined,
        customerType: customerTypeFilter,
        customerGroupId: customerGroupFilter || undefined,
        page: isTreeMode ? 1 : serverPage,
        pageSize: isTreeMode ? 500 : serverPageSize,
      })
        .then(data => {
          if (!cancelled) {
            setItems(data.items.map(normalizeCustomerDto));
            setServerTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải danh mục đối tượng', type: 'error' });
        })
        .finally(() => {
          if (cancelled) return;
          if (isNavFetch) setGridNavLoading(false);
          else endFetch();
        });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, customerTypeFilter, customerGroupFilter, isTreeMode, serverPage, serverPageSize, reloadKey, companyReloadKey, dispatch, beginFetch, endFetch, navSelectionEmpty]);

  const clientPaging = useCatalogPagination(displayRows);

  const page = isTreeMode ? clientPaging.page : serverPage;
  const setPage = isTreeMode ? clientPaging.setPage : setServerPage;
  const pageSize = isTreeMode ? clientPaging.pageSize : serverPageSize;
  const setPageSize = isTreeMode ? clientPaging.setPageSize : setServerPageSize;
  const totalCount = isTreeMode ? clientPaging.totalCount : serverTotalCount;
  const tableRows = isTreeMode ? clientPaging.pageItems : sortedItems;
  const batchSource = isTreeMode ? displayRows : sortedItems;

  const gridRows = useMemo<CustomerGridRow[]>(
    () => tableRows.map(r => ({ ...r, id: r.customerId })),
    [tableRows],
  );

  const filterSourceRows = useMemo<CustomerGridRow[]>(
    () => locallyFilteredItems.map(r => ({ ...r, id: r.customerId })),
    [locallyFilteredItems],
  );

  const selection = useCatalogListSelection({
    rows: gridRows,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.customerId,
    isRowSelectable: r => !isSharedCatalogReadOnly(r),
  });

  const resetPage = useCallback(() => {
    resetServerPage();
    clientPaging.resetPage();
  }, [clientPaging, resetServerPage]);

  const getColumnDisplayValue = useCallback(
    (row: CustomerGridRow, columnKey: string) => {
      if (columnKey === 'customerType') {
        return resolveCustomerTypeLabel(row.customerType, customerTypeOptions);
      }
      return catalogCellDisplayTextForKey(
        row as unknown as Record<string, unknown>,
        listColumns,
        columnKey,
      );
    },
    [listColumns, customerTypeOptions],
  );

  const handleColumnFilterConfirm = useCallback(
    (columnKey: string, selectedValues: string[]) => {
      setColumnFilters(prev => ({ ...prev, [columnKey]: selectedValues }));
      resetPage();
      selection.clearSelection();
    },
    [resetPage, selection],
  );

  const handleColumnFilterClear = useCallback(
    (columnKey: string) => {
      setColumnFilters(prev => {
        const next = { ...prev };
        delete next[columnKey];
        return next;
      });
      resetPage();
      selection.clearSelection();
    },
    [resetPage, selection],
  );

  const handleSortChange = useCallback(
    (sort: ErpListSortState) => {
      setSortState(sort);
      resetPage();
      selection.clearSelection();
    },
    [resetPage, selection],
  );

  const commitSearch = useCallback(
    (nextSearch?: string) => {
      const q = (nextSearch ?? searchDraft).trim();
      pulseSearch(() => {
        setLoadingMode('filter');
        setSearch(q);
        resetPage();
        selection.clearSelection();
      });
    },
    [pulseSearch, resetPage, searchDraft, selection, setLoadingMode],
  );

  const handleSearch = useCallback(() => {
    commitSearch();
  }, [commitSearch]);

  const handleSearchDraftChange = useCallback(
    (value: string) => {
      setSearchDraft(value);
      if (value.trim().length === 0 && search.trim().length > 0) {
        commitSearch('');
        return;
      }
      if (search.trim().length === 0 && groupNavSelection.kind === 'all') {
        clientPaging.resetPage();
      }
      selection.clearSelection();
    },
    [clientPaging, commitSearch, search, groupNavSelection.kind, selection],
  );

  const handleGroupNavSelect = useCallback(
    (next: CustomerGroupNavSelection) => {
      fetchLoadingKindRef.current = 'nav';
      setGroupNavSelection(next);
      resetPage();
      selection.clearSelection();
      if (isCustomerGroupNavEmpty(next, customerGroups, typeCounts)) {
        setItems([]);
        setServerTotalCount(0);
        setGridNavLoading(false);
        fetchLoadingKindRef.current = 'default';
        return;
      }
      setGridNavLoading(true);
    },
    [resetPage, selection, customerGroups, typeCounts],
  );

  const resolveCreatePreset = useCallback((): CreateCustomerPreset => {
    const selectedIds = [...selection.selectedIds];
    let parent: CustomerListItemDto | undefined;
    if (selectedIds.length === 1) {
      parent = batchSource.find(r => r.customerId === selectedIds[0]);
    } else if (selection.activeRow) {
      parent = selection.activeRow;
    }
    if (parent) {
      return { defaultParentCustomer: parent };
    }
    if (groupNavSelection.kind === 'group') {
      return { defaultCustomerGroupId: groupNavSelection.customerGroupId };
    }
    if (groupNavSelection.kind === 'type') {
      return { defaultCustomerType: groupNavSelection.customerType };
    }
    return {};
  }, [batchSource, groupNavSelection, selection.activeRow, selection.selectedIds]);

  const openAdd = () => {
    setFormViewOnly(false);
    setEditing(null);
    setCreatePreset(resolveCreatePreset());
    setCreateSessionKey(k => k + 1);
    markClean();
    setModalOpen(true);
  };

  const openView = useCallback((row: CustomerListItemDto) => {
    setFormViewOnly(true);
    setEditing(row);
    markClean();
    setModalOpen(true);
  }, [markClean]);

  const openEdit = useCallback((row: CustomerListItemDto) => {
    if (!canWrite || isSharedCatalogReadOnly(row)) {
      openView(row);
      return;
    }
    setFormViewOnly(false);
    setEditing(row);
    markClean();
    setModalOpen(true);
  }, [canWrite, markClean, openView]);

  const modalTitle = useMemo(() => {
    if (!editing) return 'Thêm đối tượng';
    if (formViewOnly) {
      return isSharedCatalogReadOnly(editing) ? 'Xem đối tượng dùng chung' : 'Xem đối tượng';
    }
    return 'Sửa đối tượng';
  }, [editing, formViewOnly]);

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setFormViewOnly(false);
      setModalOpen(false);
    });
  };

  const rowMenuHintMessage = getErpListRowMenuHint(viewMobile);

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: CustomerGridRow; x: number; y: number }) => {
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: CatalogRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          openView(row);
          break;
        case 'edit':
          openEdit(row);
          break;
        case 'history':
          toolbarBridgeRef.current?.openHistory();
          break;
        case 'renameCode':
          toolbarBridgeRef.current?.openRename();
          break;
        case 'delete': {
          if (!selection.isRowChecked(row)) {
            selection.toggleRow(row, true);
          }
          toolbarBridgeRef.current?.openDelete();
          break;
        }
        default:
          break;
      }
    },
    [rowMenu?.row, openEdit, openView, selection],
  );

  const rowMenuRow = rowMenu?.row;
  const rowMenuReadOnly = rowMenuRow ? isSharedCatalogReadOnly(rowMenuRow) : false;
  const rowMenuShowEdit = !!rowMenuRow && canWrite && !rowMenuReadOnly;
  const rowMenuShowView = !!rowMenuRow && (!canWrite || rowMenuReadOnly);

  const refresh = () => {
    setLoadingMode('filter');
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? batchSource.filter(r => !isSharedCatalogReadOnly(r)).map(r => r.customerId)
        : [...selection.selectedIds].filter(id => {
            const row = batchSource.find(r => r.customerId === id);
            return row && !isSharedCatalogReadOnly(row);
          });
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => masterService.setCustomerActive(id, false)));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} đối tượng`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deleteCustomer(id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} đối tượng`, type: 'success' });
    }
    refresh();
  };

  const getTreeRowDepth = useCallback(
    (row: CustomerGridRow) => customerRowDepth(row, depthMap),
    [depthMap],
  );

  const listGridBody = (
    <>
      {displayRows.length === 0 && !showTableLoading && !gridNavLoading ? (
        <div className={styles.empty}>
          <i className="fas fa-inbox" />
          <p>{searchDraft.trim() || search.trim() ? 'Không tìm thấy đối tượng phù hợp' : 'Không có dữ liệu'}</p>
        </div>
      ) : listColumns.length > 0 ? (
        <CatalogListGridFromSchema
          testIdPrefix={TEST_ID}
          rows={gridRows}
          page={page}
          pageSize={pageSize}
          columns={listColumns}
          schema={schema}
          selection={selection}
          getRowId={r => r.customerId}
          isRowSelectable={r => !isSharedCatalogReadOnly(r)}
          getTreeRowDepth={isTreeMode ? getTreeRowDepth : undefined}
          treeIndentPx={CUSTOMER_INDENT_PX}
          filterSourceRows={filterSourceRows}
          getColumnDisplayValue={getColumnDisplayValue}
          columnFilters={columnFilters}
          onColumnFilterConfirm={handleColumnFilterConfirm}
          onColumnFilterClear={handleColumnFilterClear}
          sortState={sortState}
          onSortChange={handleSortChange}
          getRowEditBlockedMessage={getSharedCatalogEditBlockedMessage}
          rowEditHintDismissStorageKey={catalogRowEditHintDismissStorageKey(TEST_ID)}
          onRowOpenActionMenu={handleRowOpenActionMenu}
          rowMenuHintMessage={rowMenuHintMessage}
          rowMenuHintDismissStorageKey={catalogListRowMenuHintDismissStorageKey(TEST_ID)}
          enableRowMenuLongPress={viewMobile}
        />
      ) : schemaLoading || showTableLoading ? null : (
        <div className={styles.empty}><i className="fas fa-inbox" /><p>Không tải được cấu hình cột — thử Làm mới</p></div>
      )}
    </>
  );

  return (
    <CatalogCodeReplaceProvider catalogKind={CATALOG_KIND}>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        className={viewMobile ? undefined : LIN_TREE_GRID_TABLE_CARD_CLASS}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={gridRows}
        onAdd={openAdd}
        onEdit={openEdit}
        toolbarBridgeRef={toolbarBridgeRef}
        onRefresh={refresh}
        toolbarExtraLeftActions={(
          <CatalogListExportButton
            testIdPrefix={TEST_ID}
            onExport={() => exportCustomersCsv({ search: search || undefined })}
          />
        )}
        onBatchDelete={handleBatchDelete}
        canAdd={groupOpts.length > 0}
        showSchemaConfig
        onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
        proposalFieldDefs={proposalFieldDefs.length > 0 ? proposalFieldDefs : undefined}
        page={page}
        pageSize={pageSize}
        onPageChange={p => { setLoadingMode('page'); setPage(p); selection.clearSelection(); }}
        onPageSizeChange={size => { setLoadingMode('filter'); setPageSize(size); }}
        showTableLoading={showTableLoading}
        pageLoading={pageLoading || gridNavLoading}
        header={{ title: 'Danh mục đối tượng', titleIconClass: 'fas fa-handshake' }}
        listTitle="Danh sách đối tượng"
        listRowMenuHelp
        filtersTestId={`${TEST_ID}-filters`}
        filterMaxWidthPx={1000}
        filters={(
          <CatalogListHeaderFilters testIdPrefix={TEST_ID} filterMaxWidthPx={1000}>
            <LinListFilterField testId={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                placeholder="Tìm mã, tên..."
                value={searchDraft}
                onChange={handleSearchDraftChange}
                onSearch={handleSearch}
                testId={`${TEST_ID}-search-text`}
              />
            </LinListFilterField>
            {viewMobile ? (
              <LinListFilterField testId={`${TEST_ID}-field-customerGroupFilter`}>
                <Select
                  label="Lọc nhóm"
                  value={customerGroupFilter}
                  placeholder="Tất cả nhóm"
                  className={selectPlaceholderClass(customerGroupFilter)}
                  onChange={e => {
                    const groupId = e.target.value;
                    handleGroupNavSelect(
                      groupId
                        ? { kind: 'group', customerGroupId: groupId }
                        : { kind: 'all' },
                    );
                  }}
                  options={filterGroupOpts}
                />
              </LinListFilterField>
            ) : null}
          </CatalogListHeaderFilters>
        )}
        schemaEditorModal={(
          <CatalogUiSchemaEditorModal
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            isOpen={schemaEditorOpen}
            onClose={() => setSchemaEditorOpen(false)}
            onSaved={() => {
              reloadSchema();
              refresh();
            }}
            showMasterCodeConfig
          />
        )}
        extraModals={(
          <>
            <CatalogRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showEdit={rowMenuShowEdit}
              showView={rowMenuShowView}
              showHistory={!!rowMenuRow}
              showRename={rowMenuShowEdit}
              showDelete={rowMenuShowEdit}
            />
            <LeaveConfirmModal {...leaveConfirmModalProps} />
          </>
        )}
      >
        {viewMobile ? (
          listGridBody
        ) : (
          <LinTreeGridLayout
            testIdPrefix={TEST_ID}
            gridLoading={gridNavLoading}
            sidebar={(
              <CustomerGroupCascadeNav
                testIdPrefix={TEST_ID}
                groups={customerGroups}
                selection={groupNavSelection}
                onSelect={handleGroupNavSelect}
                totalCount={allTypeTotalCount}
                typeCounts={typeCounts}
              />
            )}
          >
            {listGridBody}
          </LinTreeGridLayout>
        )}
      </CatalogListMasterLinPageLayout>

      <CustomerForm
        key={editing?.customerId ?? (modalOpen ? `create-${createSessionKey}` : 'closed')}
        testIdPrefix={TEST_ID}
        editing={editing}
        initFormName={initFormName}
        defaultCustomerGroupId={createPreset.defaultCustomerGroupId}
        defaultParentCustomer={createPreset.defaultParentCustomer}
        defaultCustomerType={createPreset.defaultCustomerType}
        listGroupOptions={listGroupOptions}
        companyName={editing?.companyName ?? sessionCompanyName}
        sharedCatalog={sharedForm}
        readOnly={formViewOnly}
        shellVariant="slideout"
        slideoutOpen={modalOpen}
        slideoutTitle={modalTitle}
        onDirtyChange={onDirtyChange}
        onCancel={closeFormModal}
        onSaved={() => {
          setModalOpen(false);
          refresh();
        }}
        onValidationFailed={() => scrollToFirstFieldError(TEST_ID)}
      />
    </CatalogCodeReplaceProvider>
  );
};

export default DoiTuongPage;
