import React, { useMemo } from 'react';
import {
  LinTreeNav,
  type LinTreeNavNode,
  type LinTreeNavSelection,
} from '@linm-soft-org/linm-web-common-components';
import type { CustomerGroupDto } from '../../../services/master/models';
import {
  CUSTOMER_GROUP_ANALYSIS_TYPE_ORDER,
  CUSTOMER_TYPE_LABELS,
  collectCustomerGroupAncestorIds,
  customerGroupNavRootsByMasterType,
  customerGroupRowCellStyle,
  type CustomerGroupAnalysisType,
  type CustomerGroupNavSelection,
  type CustomerGroupTreeNode,
} from '../../../utils/customerGroupTree';

export type { CustomerGroupNavSelection };

type Props = {
  testIdPrefix: string;
  groups: CustomerGroupDto[];
  selection: CustomerGroupNavSelection;
  onSelect: (next: CustomerGroupNavSelection) => void;
  totalCount: number;
  typeCounts: Partial<Record<CustomerGroupAnalysisType, number>>;
};

function toLinTreeNavSelection(selection: CustomerGroupNavSelection): LinTreeNavSelection {
  if (selection.kind === 'all') return { kind: 'all' };
  if (selection.kind === 'type') return { kind: 'section', sectionId: selection.customerType };
  return { kind: 'node', nodeId: selection.customerGroupId };
}

function fromLinTreeNavSelection(selection: LinTreeNavSelection): CustomerGroupNavSelection {
  if (selection.kind === 'all') return { kind: 'all' };
  if (selection.kind === 'section') {
    return { kind: 'type', customerType: selection.sectionId as CustomerGroupAnalysisType };
  }
  return { kind: 'group', customerGroupId: selection.nodeId };
}

function mapGroupNode(node: CustomerGroupTreeNode): LinTreeNavNode {
  return {
    nodeId: node.customerGroupId,
    code: node.code,
    label: node.name,
    count: node.customerCount,
    level: node.level,
    rowStyle: node.level === 1 ? customerGroupRowCellStyle(node) : undefined,
    children: node.children.map(mapGroupNode),
  };
}

export const CustomerGroupCascadeNav: React.FC<Props> = ({
  testIdPrefix,
  groups,
  selection,
  onSelect,
  totalCount,
  typeCounts,
}) => {
  const treeByType = useMemo(
    () => customerGroupNavRootsByMasterType(groups),
    [groups],
  );

  const sections = useMemo(
    () => CUSTOMER_GROUP_ANALYSIS_TYPE_ORDER.map(type => ({
      sectionId: type,
      label: CUSTOMER_TYPE_LABELS[type] ?? type,
      count: typeCounts[type],
      nodes: (treeByType.get(type) ?? []).map(mapGroupNode),
    })),
    [treeByType, typeCounts],
  );

  return (
    <LinTreeNav
      testIdPrefix={testIdPrefix}
      title="Nhóm đối tượng"
      selection={toLinTreeNavSelection(selection)}
      onSelect={next => onSelect(fromLinTreeNavSelection(next))}
      allRow={{ label: 'Tất cả', count: totalCount }}
      sections={sections}
      defaultExpandedSectionIds={[...CUSTOMER_GROUP_ANALYSIS_TYPE_ORDER]}
      resolveAncestorNodeIds={nodeId => collectCustomerGroupAncestorIds(nodeId, groups)}
    />
  );
};
